{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-reconnect-spec-plus-pump-update-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中的进料流量缺失、泵出口压力目标无效、泵效率范围告警，以及加热器出口断连问题生成候选提案；其中断连仅能提出保护性连接占位，具体下游对象证据不足。",
      "issues": [
        {
          "title": "Transfer Pump Feed 缺少流量规格",
          "description": "诊断指出 feed-93 缺少流量规格，当前流股已有压力和温度规格但没有流量规格。",
          "severity": "error",
          "citations": [
            "diag-2",
            "flowdoc-stream-1"
          ]
        },
        {
          "title": "Transfer Pump 出口压力目标低于入口压力",
          "description": "诊断指出 pump-14 的 outlet_pressure_target_kpa 低于入口压力；当前进料压力为 210 kPa，而泵配置目标为 170 kPa，且泵出口流股压力为 178 kPa。",
          "severity": "error",
          "citations": [
            "diag-3",
            "flowdoc-unit-1",
            "flowdoc-stream-1",
            "flowdoc-stream-2"
          ]
        },
        {
          "title": "Transfer Pump 效率参数超出推荐范围",
          "description": "诊断指出 pump-14 的 efficiency_percent=54 超出推荐操作范围。",
          "severity": "warning",
          "citations": [
            "diag-4",
            "flowdoc-unit-1"
          ]
        },
        {
          "title": "Trim Heater Outlet 93 缺少下游连接",
          "description": "诊断指出 heater-outlet-93 未连接到任何下游 consumer 或 export sink，当前快照显示求解状态为 invalid_topology。",
          "severity": "error",
          "citations": [
            "diag-1",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Transfer Pump Feed 添加流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-93"
          },
          "rationale": "feed-93 已被选中且诊断直接指出缺少流量规格；由于输入中没有给出可信的流量数值，建议仅添加可审查的流量规格占位，而不是填入臆测数值。",
          "patch": {
            "spec_placeholders": {
              "flow_rate": {
                "required": true,
                "reason": "STREAM_SPEC_MISSING: Transfer Pump Feed is missing flow rate specification.",
                "suggested_source": "user_or_design_basis"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-stream-1"
          ],
          "confidence": 0.88
        },
        {
          "action": "candidate_edit",
          "title": "将 Transfer Pump 出口压力目标修正为不低于入口压力的占位目标",
          "target": {
            "type": "unit",
            "id": "pump-14"
          },
          "rationale": "pump-14 已被选中且诊断指出出口压力目标低于入口压力；当前入口流股压力为 210 kPa，而泵配置 outlet_pressure_target_kpa 为 170 kPa。为避免擅自确定设计压升，建议把目标压力改为需确认的局部参数占位。",
          "patch": {
            "parameter_placeholders": {
              "outlet_pressure_target_kpa": {
                "required": true,
                "constraint": "must_be_greater_than_or_equal_to_inlet_pressure_kpa",
                "reference_inlet_pressure_kpa": 210,
                "current_value": 170,
                "suggested_source": "user_or_design_pressure_target"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ],
          "confidence": 0.82
        },
        {
          "action": "candidate_edit",
          "title": "将 Transfer Pump 效率参数标记为需确认的范围修正",
          "target": {
            "type": "unit",
            "id": "pump-14"
          },
          "rationale": "pump-14 已被选中且诊断直接指出 efficiency_percent=54 超出推荐操作范围；输入未提供推荐范围边界，因此仅提出参数占位以便确认，而不直接替换为臆测效率。",
          "patch": {
            "parameter_placeholders": {
              "efficiency_percent": {
                "required": true,
                "current_value": 54,
                "constraint": "within_recommended_operating_range",
                "suggested_source": "equipment_datasheet_or_user_confirmation"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-4",
            "flowdoc-unit-1"
          ],
          "confidence": 0.76
        },
        {
          "action": "candidate_edit",
          "title": "为 Trim Heater Outlet 93 添加下游连接占位",
          "target": {
            "type": "stream",
            "id": "heater-outlet-93"
          },
          "rationale": "heater-outlet-93 已被选中且诊断指出未连接到任何下游 consumer 或 export sink，当前快照为 invalid_topology。由于输入中没有给出具体下游单元或导出汇，建议仅添加连接占位供确认，避免直接重连到未知对象。",
          "patch": {
            "connection_placeholder": {
              "target_unit_id_or_export_sink": {
                "required": true,
                "reason": "STREAM_DISCONNECTED: downstream consumer or export sink is missing.",
                "allowed_resolution": [
                  "existing_downstream_unit_if_confirmed",
                  "export_sink_if_confirmed"
                ],
                "note": "Heater outlet state should remain explanatory context until downstream sink is restored."
              }
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "diag-5",
            "flowdoc-stream-3",
            "snapshot-1"
          ],
          "confidence": 0.7
        }
      ],
      "citations": [
        "diag-2",
        "diag-3",
        "diag-4",
        "diag-1",
        "diag-5",
        "flowdoc-stream-1",
        "flowdoc-unit-1",
        "flowdoc-stream-3",
        "snapshot-1"
      ]
    }
  ]
}
